// src/printLabel.js
// Abre una ventana de impresión con la etiqueta rediseñada (100x150mm)

const LOGO_B64  = "data:image/png;base64,";
const FONDO_B64 = "data:image/jpeg;base64,";

export default function printLabel(delivery) {
  const { code, label = {} } = delivery;
  const to = label.to || {};
  const orderNumber = label.orderNumber || "";
  const trackingUrl = `https://tracking.robustheit.cl/?code=${code}`;

  const html = `<!DOCTYPE html>
<html lang="es"><head><meta charset="UTF-8"/>
<title>Etiqueta ${code}</title>
<script src="https://cdnjs.cloudflare.com/ajax/libs/qrcodejs/1.0.0/qrcode.min.js"><\/script>
<style>
*{margin:0;padding:0;box-sizing:border-box;}
body{font-family:Arial,Helvetica,sans-serif;background:#fff;}
@page{size:100mm 150mm;margin:0;}
@media print{body{-webkit-print-color-adjust:exact;print-color-adjust:exact;}}
.label{width:100mm;height:150mm;border-radius:3mm;overflow:hidden;display:flex;flex-direction:column;position:relative;background:#fff;}
.label-bg{position:absolute;top:0;left:0;width:100%;height:100%;background-image:url(${FONDO_B64});background-size:cover;background-position:center;opacity:0.12;pointer-events:none;z-index:0;}
.label > *:not(.label-bg){position:relative;z-index:1;}
.hdr{background:#F5A623;padding:3.5mm 0 0;text-align:center;flex-shrink:0;}
.hdr img{height:16mm;object-fit:contain;display:block;margin:0 auto;}
.hdr-stripe{height:1.2mm;background:#2D3A8C;margin-top:2.5mm;}
.meta{background:#f7f7f7;display:flex;padding:2mm 4mm;border-bottom:0.4mm solid #e0e0e0;flex-shrink:0;}
.meta-col{flex:1;}
.meta-col+.meta-col{border-left:0.4mm solid #e0e0e0;padding-left:3mm;}
.meta-lbl{font-size:5.5pt;font-weight:700;letter-spacing:1.5px;color:#F5A623;margin-bottom:0.8mm;}
.meta-lbl.blue{color:#2D3A8C;}
.meta-val{font-size:9pt;color:#bbb;letter-spacing:1px;}
.meta-val.code{font-family:"Courier New",monospace;font-size:13pt;font-weight:900;color:#1a1a1a;letter-spacing:2px;}
.empresa{text-align:center;font-size:5pt;color:#bbb;letter-spacing:2.5px;padding:1.5mm 0 1mm;border-bottom:0.3mm solid #eee;flex-shrink:0;}
.qr-wrap{display:flex;justify-content:center;padding:3mm 0 2.5mm;flex-shrink:0;}
.qr-inner{background:#1a1a1a;border-radius:2.5mm;padding:2.5mm;}
.comuna{text-align:center;font-size:17pt;font-weight:900;font-family:"Arial Black",Arial,sans-serif;color:#1a1a1a;letter-spacing:1.5px;padding:2mm 4mm 2.5mm;flex-shrink:0;}
.divider{height:0.4mm;background:#e0e0e0;margin:0 4mm;flex-shrink:0;}
.dest{padding:2mm 4mm 1.5mm;flex-shrink:0;}
.dest-lbl{font-size:5.5pt;font-weight:700;letter-spacing:2px;color:#2D3A8C;margin-bottom:1.5mm;}
.dest-name{font-size:11pt;font-weight:700;color:#1a1a1a;margin-bottom:1mm;}
.dest-addr{font-size:7.5pt;color:#555;line-height:1.4;}
.dest-phone{font-size:7pt;color:#888;margin-top:0.8mm;}
.nota{margin:1.5mm 3mm;background:#FFF8EC;border:0.3mm solid #F5A623;border-radius:1.5mm;padding:1.5mm 3mm;flex-shrink:0;}
.nota-lbl{font-size:5pt;font-weight:700;letter-spacing:2px;color:#F5A623;margin-bottom:1mm;}
.nota-txt{font-size:7pt;color:#555;}
</style></head><body>
<div class="label">
  <div class="label-bg"></div>
  <div class="hdr">
    <img src="${LOGO_B64}" alt="Robustheit"/>
    <div class="hdr-stripe"></div>
  </div>
  <div class="meta">
    <div class="meta-col">
      <div class="meta-lbl">N° PEDIDO</div>
      <div class="meta-val">${orderNumber || "— — — — —"}</div>
    </div>
    <div class="meta-col">
      <div class="meta-lbl blue">CÓDIGO</div>
      <div class="meta-val code">${code}</div>
    </div>
  </div>
  <div class="empresa">ROBUSTHEIT PROPERTY SPA</div>
  <div class="qr-wrap">
    <div class="qr-inner" id="qr"></div>
  </div>
  <div class="comuna">${(to.city || "").toUpperCase()}</div>
  <div class="divider"></div>
  <div class="dest">
    <div class="dest-lbl">DESTINATARIO</div>
    <div class="dest-name">${to.name || ""}</div>
    <div class="dest-addr">${[to.address, to.city].filter(Boolean).join(", ")}</div>
    ${to.phone ? `<div class="dest-phone">${to.phone}</div>` : ""}
  </div>
  ${label.notes ? `
  <div class="nota">
    <div class="nota-lbl">NOTA</div>
    <div class="nota-txt">${label.notes}</div>
  </div>` : ""}
</div>
<script>
window.onload = function() {
  new QRCode(document.getElementById("qr"), {
    text: "${trackingUrl}",
    width: 110, height: 110,
    colorDark: "#ffffff", colorLight: "#1a1a1a",
    correctLevel: QRCode.CorrectLevel.M
  });
  setTimeout(() => window.print(), 700);
};
<\/script></body></html>`;

  const win = window.open("", "_blank", "width=420,height=650");
  win.document.write(html);
  win.document.close();
}